-- =====================================================
-- File:        test_data.sql
-- Purpose:     Seed data for PrimeAutocare.
--              Generated; keys are explicit so FKs stay stable.
-- Created:     2026-07-23
-- =====================================================
-- All employees share the development password: Passw0rd!

TRUNCATE PAYMENT, INVOICE, JOBS, ATTENDANCE, VEHICLE, CUSTOMER, JOB, EMPLOYEE RESTART IDENTITY CASCADE;

-- EMPLOYEE (30, including a fixed admin/admin123 login)

-- JOB (job type catalog) (30)

-- CUSTOMER (35)

-- VEHICLE (40)

-- JOBS (spanning the last 20 days, plus today's open jobs)

-- INVOICE + PAYMENT (one invoice per completed job, some fully paid, some partial/unpaid)

-- ATTENDANCE (past 20 days for each employee, weekdays only, mostly clocked out; today may be open)

-- Explicit-key inserts above don't advance the identity sequences, so fix them up
-- to the max value used; otherwise the app's next INSERT collides on the PK.
SELECT setval('employee_seq', (SELECT COALESCE(MAX(SUBSTRING(emp_no FROM 3)::INT), 0) FROM EMPLOYEE));
SELECT setval('job_seq', (SELECT COALESCE(MAX(SUBSTRING(job_no FROM 3)::INT), 0) FROM JOB));
SELECT setval('customer_seq', (SELECT COALESCE(MAX(SUBSTRING(cust_no FROM 3)::INT), 0) FROM CUSTOMER));
SELECT setval('vehicle_seq', (SELECT COALESCE(MAX(SUBSTRING(vehi_id FROM 3)::INT), 0) FROM VEHICLE));
SELECT setval('jobs_seq', (SELECT COALESCE(MAX(SUBSTRING(job_id FROM 3)::INT), 0) FROM JOBS));
SELECT setval('invoice_seq', (SELECT COALESCE(MAX(SUBSTRING(inv_no FROM 3)::INT), 0) FROM INVOICE));
SELECT setval('payment_seq', (SELECT COALESCE(MAX(SUBSTRING(pay_no FROM 3)::INT), 0) FROM PAYMENT));
SELECT setval('attendance_seq', (SELECT COALESCE(MAX(SUBSTRING(att_id FROM 3)::INT), 0) FROM ATTENDANCE));

